# weather.py - 天气查询核心逻辑
import requests

def get_weather(city):
    url = f"https://wttr.in/{city}?format=%C|%t|%h"
    try:
        response = requests.get(url, timeout=5)
        response.raise_for_status()
        return response.text
    except requests.RequestException as e:
        return f"请求失败: {e}"

