import re

def parse_weather(raw_text):
    parts = raw_text.strip().split("|")
    if len(parts) >= 3:
        return {
            "condition": parts[0],
            "temperature": parts[1],
            "humidity": parts[2]
        }
    return None

def display_weather(data, city):
    if data is None:
        print("无法解析天气数据")
        return
    print(f"\n🌍 {city} 的当前天气:")
    print(f"  天气状况: {data['condition']}")
    print(f"  温度: {data['temperature']}")
    print(f"  湿度: {data['humidity']}")

