# renamer.py - 重命名核心逻辑
import os
from pathlib import Path

def list_files(folder_path):
    path = Path(folder_path)
    if not path.exists():
        print("文件夹不存在!")
        return []
    files = [f for f in path.iterdir() if f.is_file()]
    return files

def add_prefix(files, prefix):
    for f in files:
        new_name = prefix + f.name
        new_path = f.parent / new_name
        f.rename(new_path)
        print(f"{f.name} -> {new_name}")

def rename_with_index(files, prefix="file"):
    for index, f in enumerate(files, start=1):
        ext = f.suffix
        new_name = f"{prefix}_{index:03d}{ext}"
        new_path = f.parent / new_name
        f.rename(new_path)
        print(f"{f.name} -> {new_name}")

def replace_in_name(files, old, new):
    for f in files:
        if old in f.name:
            new_name = f.name.replace(old, new)
            new_path = f.parent / new_name
            f.rename(new_path)
            print(f"{f.name} -> {new_name}")

def preview_changes(files, operation, **kwargs):
    print("\n=== 预览模式 ===")
    print("以下文件将被重命名:")
    for f in files:
        if operation == "prefix":
            new_name = kwargs["prefix"] + f.name
        elif operation == "index":
            new_name = f"{kwargs.get('idx_prefix', 'file')}_{files.index(f)+1:03d}{f.suffix}"
        elif operation == "replace":
            new_name = f.name.replace(kwargs["old"], kwargs["new"])
        print(f"  {f.name}  ->  {new_name}")

    confirm = input("\n确认执行? (y/n): ").lower()
    return confirm == 'y'

