# main.py - 程序入口
from renamer import list_files, add_prefix, rename_with_index, replace_in_name, preview_changes

def main():
    print("=== 文件批量重命名工具 ===")
    folder = input("请输入文件夹路径: ")
    files = list_files(folder)

    if not files:
        print("没有找到文件")
        return

    print(f"\n找到 {len(files)} 个文件")
    print("\n1. 添加前缀\n2. 按序号重命名\n3. 替换文件名中的文字")

    choice = input("请选择操作: ")
    if choice == "1":
        prefix = input("输入前缀: ")
        if preview_changes(files, "prefix", prefix=prefix):
            add_prefix(list_files(folder), prefix)
    elif choice == "2":
        prefix = input("序号前缀 (默认file): ") or "file"
        if preview_changes(files, "index", idx_prefix=prefix):
            rename_with_index(list_files(folder), prefix)
    elif choice == "3":
        old = input("要替换的文字: ")
        new = input("替换成: ")
        if preview_changes(files, "replace", old=old, new=new):
            replace_in_name(list_files(folder), old, new)

if __name__ == "__main__":
    main()

