const API_URL = 'https://api.github.com/users/';

async function searchUser() {
    const username = document.getElementById('username').value.trim();
    const errorEl = document.getElementById('error');
    const profileEl = document.getElementById('profile');

    if (!username) { showError('请输入用户名'); profileEl.style.display = 'none'; return; }
    errorEl.style.display = 'none';

    try {
        const response = await fetch(API_URL + username);
        if (response.status === 404) throw new Error('用户不存在');
        if (!response.ok) throw new Error('请求失败: ' + response.status);
        const data = await response.json();
        displayProfile(data);
    } catch (err) { showError(err.message); profileEl.style.display = 'none'; }
}

function displayProfile(data) {
    document.getElementById('avatar').src = data.avatar_url;
    document.getElementById('name').textContent = data.name || data.login;
    document.getElementById('bio').textContent = data.bio || '暂无简介';
    document.getElementById('repos').textContent = data.public_repos;
    document.getElementById('followers').textContent = data.followers;
    document.getElementById('created').textContent = new Date(data.created_at).toLocaleDateString('zh-CN');
    document.getElementById('link').href = data.html_url;
    document.getElementById('profile').style.display = 'block';
}

function showError(msg) {
    const errorEl = document.getElementById('error');
    errorEl.textContent = msg; errorEl.style.display = 'block';
}

document.getElementById('username').addEventListener('keypress', function(e) {
    if (e.key === 'Enter') searchUser();
});

